package jetbrains.mps.ide.common;

/*Generated by MPS */

import org.jetbrains.annotations.Nullable;
import com.intellij.openapi.vfs.VirtualFile;
import com.intellij.openapi.project.Project;
import com.intellij.psi.search.FilenameIndex;
import com.intellij.psi.search.GlobalSearchScope;
import jetbrains.mps.internal.collections.runtime.Sequence;
import jetbrains.mps.internal.collections.runtime.IWhereFilter;
import com.intellij.openapi.progress.ProcessCanceledException;
import com.intellij.openapi.fileEditor.FileEditor;
import com.intellij.openapi.fileEditor.FileEditorManager;
import com.intellij.openapi.fileEditor.TextEditor;
import com.intellij.openapi.editor.LogicalPosition;
import com.intellij.openapi.editor.ScrollType;

public class FileOpenUtil {
  public FileOpenUtil() {
  }

  @Nullable
  public static VirtualFile findFile(Project project, String unitName, String fileName) {
    final String fullFileName;
    if (!(unitName.endsWith(fileName))) {
      int lastDot = unitName.lastIndexOf('.');
      if (lastDot == -1) {
        fullFileName = fileName;
      } else {
        // this seems to be an odd way to construct file path from "qualified.ClassName" and "ClassName.java" 
        fullFileName = unitName.substring(0, lastDot).replace('.', '/') + '/' + fileName;
      }
    } else {
      fullFileName = unitName.replace('.', '/');
    }
    try {
      Iterable<VirtualFile> vfByName = FilenameIndex.getVirtualFilesByName(project, fileName, GlobalSearchScope.allScope(project));
      return Sequence.fromIterable(vfByName).where(new IWhereFilter<VirtualFile>() {
        public boolean accept(VirtualFile it) {
          return it.getPath().endsWith(fullFileName);
        }
      }).first();
    } catch (ProcessCanceledException ex) {
      //  ignore, can not report anything,pretend we didn't find any 
      return null;
    }
  }

  public static void openFile(Project project, VirtualFile file, int lineNumber) {
    FileEditor[] result = FileEditorManager.getInstance(project).openFile(file, true, true);
    if (result.length == 1 && result[0] instanceof TextEditor) {
      TextEditor textEditor = (TextEditor) result[0];
      LogicalPosition position = new LogicalPosition(lineNumber - 1, 0);
      textEditor.getEditor().getCaretModel().moveToLogicalPosition(position);
      textEditor.getEditor().getScrollingModel().scrollToCaret(ScrollType.MAKE_VISIBLE);
    }
  }
}
